// Extract message details and check authorisation
const item = $input.first().json;
// Handle both regular messages and callback queries (button presses)
const isCallback = !!item.callback_query;
const message = isCallback ? item.callback_query.message : item.message;
const callbackData = isCallback ? item.callback_query.data : null;
const callbackId = isCallback ? item.callback_query.id : null;
const chatId = message?.chat?.id || item.callback_query?.message?.chat?.id;
const userId = isCallback ? item.callback_query.from.id : message?.from?.id;
const firstName = isCallback ? item.callback_query.from.first_name : message?.from?.first_name;
const text = isCallback ? callbackData : (message?.text || message?.caption || '').trim();
// Authorised users
const TYSON_ID = 1375806243;
const EMMA_ID = 1318710237;
const AUTHORISED = [TYSON_ID, EMMA_ID];
const isTyson = userId === TYSON_ID;
const isAuthorised = AUTHORISED.includes(userId);
// Extract file info (for ad creative uploads)
const doc = message?.document;
const photo = message?.photo;
const video = message?.video;
const fileId = doc?.file_id || (photo ? photo[photo.length-1]?.file_id : null) || video?.file_id || null;
const fileName = doc?.file_name || (photo ? 'photo.jpg' : null) || (video ? 'video.mp4' : null) || null;
const fileType = doc ? 'document' : (photo ? 'photo' : (video ? 'video' : null));
return [{
  json: {
    chatId,
    userId,
    firstName,
    text,
    isCallback,
    callbackData,
    callbackId,
    isTyson,
    isAuthorised,
    rawMessage: message,
    fileId,
    fileName,
    fileType
  }
}];

const apiResponse = $input.first().json;
const raw = apiResponse.content?.[0]?.text || '{}';
let parsed = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
} catch(e) {
  parsed = { intent: 'UNKNOWN' };
}
const ctx = $('Build Anthropic Request').first().json;
return [{ json: { ...parsed, chatId: ctx.chatId, userId: ctx.userId, firstName: ctx.firstName, isTyson: ctx.isTyson, originalText: ctx.originalText, isCallback: ctx.isCallback, callbackData: ctx.callbackData } }];

// Format copy variants for Telegram (max 4096 chars per message)
const copyData = $input.first().json;
const copy = copyData.copy || copyData.copy_variants || 'Copy generation failed — please try again.';
const chatId = $('Parse Intent').first().json.chatId;
const isTyson = $('Parse Intent').first().json.isTyson;

// Truncate if needed for Telegram
const maxLen = 3800;
const truncated = copy.length > maxLen ? copy.substring(0, maxLen) + '\n\n_[Truncated — full copy sent to email]_' : copy;

let approvalNote = '';
if (isTyson) {
  approvalNote = '\n\n✅ *Reply with the variant number (1-5) to approve, or say "iterate on [number]" for changes.*';
} else {
  approvalNote = '\n\n_Tyson will be notified to review and approve._';
}

return [{
  json: {
    chatId,
    isTyson,
    message: `📝 *Ad Copy Variants Ready*\n\n${truncated}${approvalNote}`
  }
}];

// If Emma requested copy, also notify Tyson for approval
const data = $('Format Copy Reply').first().json;
const isTyson = data.isTyson;
const TYSON_CHAT = 1375806243;

if (!isTyson) {
  return [{
    json: {
      chatId: TYSON_CHAT,
      message: `🔔 *Approval Needed*\n\nEmma has requested new ad copy. Check your chat or email to review the variants and reply with your selection.`
    }
  }];
}
// If Tyson requested, no separate notification needed
return [{ json: { chatId: TYSON_CHAT, message: null, skip: true } }];

const msgData = $('Parse Message').first().json;
const userText = (msgData.text || '').replace(/'/g, "\'");
const body = {
  model: 'claude-haiku-4-5',
  max_tokens: 300,
  messages: [{
    role: 'user',
    content: `You are an intent classifier for a Facebook Ads management bot. Be generous — if a message is close to an intent, pick it rather than UNKNOWN.

Classify this message into ONE intent:
- COPY: wants ad copy written/generated (e.g. "write me 5 variants", "write copy for", "ad copy", "5 copy variants")
- BRIEF: wants a creative brief, script, or content plan
- REPORT: wants performance data or stats
- APPROVE: approving a copy variant (e.g. "approve variant 3", "go with 2", "use 1")
- ITERATE: wants to refine/change a copy variant (e.g. "iterate on variant 2", "make hook shorter", "refine 3", "tweak variant 1")
- REJECT: rejecting all variants
- HELP: wants to know what the bot can do
- AD_CREATION: wants to create a new ad in Meta Ads Manager (e.g. "create new ad", "set up an ad", "launch a campaign", "create ad in")
- RESEARCH: wants to research competitor ads, save a competitor ad, or view swipe file (e.g. "research ads for [brand]", "look up competitor ads", "save this ad", "show me my swipe file")
- UNKNOWN: genuinely unclear, off-topic, or a casual greeting with no clear intent

Extract if present: offer, angle, format (Reel/static/story/single image/carousel), creator (Tyson or Emma), hook_style, feedback, variant_number (for ITERATE/APPROVE), brand (for RESEARCH).

Message: "${userText}"
Reply ONLY with valid JSON: {"intent":"COPY","offer":"","angle":"","format":"","creator":"","hook_style":"","feedback":"","variant_number":"","brand":""}`
  }]
};
return [{
  json: {
    body: JSON.stringify(body),
    chatId: msgData.chatId,
    userId: msgData.userId,
    firstName: msgData.firstName,
    isTyson: msgData.isTyson,
    originalText: msgData.text,
    isCallback: msgData.isCallback,
    callbackData: msgData.callbackData
  }
}];

const data = $input.first().json;
const msgData = $('Parse Message').first().json;
const sessions = data.sessions || [];
const validSessions = sessions.filter(s => s && s.id && s.step && s.step !== 'start');
const activeSession = validSessions.length > 0 ? validSessions[0] : null;
return [{ json: {
  ...msgData,
  hasActiveAdSession: !!activeSession,
  activeAdSession: activeSession
}}];

// Get data from Parse Intent (which has chatId, userId, firstName, text)
// The Ack node doesn't pass through the original data, so we need to go back
// to the Parse Intent node output
const ctx = $input.first().json;
// ctx here is the Telegram API response from Ad Creation Acknowledgement
// We need to get the original message data - use $('Parse Intent') to reference it
const parseIntentData = $('Parse Intent').first().json;
return [{
  json: {
    chatId: parseIntentData.chatId,
    userId: parseIntentData.userId,
    firstName: parseIntentData.firstName,
    text: parseIntentData.originalText || parseIntentData.text || '',
    step: 'start'
  }
}];

// Parse the text response from Supabase (always a string now)
const allItems = $input.all();
let sessions = [];

for (const item of allItems) {
  const j = item.json;
  // When responseFormat is 'text', the response is in j.data as a string
  const rawText = j.data || j.body || '';
  if (rawText) {
    try {
      const parsed = JSON.parse(rawText);
      if (Array.isArray(parsed) && parsed.length > 0) {
        sessions = parsed;
      }
    } catch(e) {
      // Not valid JSON, ignore
    }
  }
}

return [{ json: { sessions } }];

const ctx = $input.first().json;
return [{
  json: {
    chatId: ctx.chatId,
    userId: ctx.userId,
    firstName: ctx.firstName,
    text: ctx.text || '',
    step: ctx.activeAdSession ? ctx.activeAdSession.step : 'start',
    // Pass file data through for asset upload step
    fileId: ctx.fileId || null,
    fileName: ctx.fileName || null,
    fileType: ctx.fileType || null
  }
}];
